//! Type conversions between local and distributed types.

use crate::record::region::{RegionRecord, RegionState};

/// Trait for converting between local and distributed types.
pub trait LocalToDistributed {
    type Distributed;

    /// Converts to the distributed equivalent.
    fn to_distributed(&self) -> Self::Distributed;
}

/// Trait for converting from distributed to local types.
pub trait DistributedToLocal {
    type Local;

    /// Converts to the local equivalent.
    fn to_local(&self) -> Self::Local;

    /// Returns true if lossless conversion is possible.
    fn is_lossless(&self) -> bool;
}

impl LocalToDistributed for RegionState {
    type Distributed = DistributedRegionState;

    fn to_distributed(&self) -> DistributedRegionState {
        match self {
            Self::Open => DistributedRegionState::Active,
            Self::Closing | Self::Draining | Self::Finalizing => {
                DistributedRegionState::Closing
            }
            Self::Closed => DistributedRegionState::Closed,
        }
    }
}

impl DistributedToLocal for DistributedRegionState {
    type Local = RegionState;

    fn to_local(&self) -> RegionState {
        match self {
            Self::Initializing | Self::Active | Self::Degraded | Self::Recovering => {
                RegionState::Open
            }
            Self::Closing => RegionState::Closing,
            Self::Closed => RegionState::Closed,
        }
    }

    fn is_lossless(&self) -> bool {
        // Some distributed states map to the same local state
        matches!(
            self,
            Self::Active | Self::Closing | Self::Closed
        )
    }
}

impl LocalToDistributed for RegionRecord {
    type Distributed = RegionSnapshot;

    fn to_distributed(&self) -> RegionSnapshot {
        RegionSnapshot {
            region_id: self.id,
            state: self.state,
            timestamp: Time::ZERO, // Must be set by caller
            sequence: 0,          // Must be set by caller
            tasks: self.tasks.iter().map(|&id| TaskSnapshot {
                task_id: id,
                state: TaskState::Running, // Simplified
                priority: 0,
            }).collect(),
            children: self.children.clone(),
            finalizer_count: self.finalizer_count() as u32,
            budget: BudgetSnapshot::from(&self.budget),
            cancel_reason: self.cancel_reason.as_ref().map(|r| r.to_string()),
            parent: self.parent,
            metadata: vec![],
        }
    }
}

impl DistributedToLocal for RegionSnapshot {
    type Local = RegionRecord;

    fn to_local(&self) -> RegionRecord {
        let mut record = RegionRecord::new(
            self.region_id,
            self.parent,
            self.budget.to_budget(),
        );
        record.state = self.state;
        record.children = self.children.clone();
        // Note: Tasks and finalizers need to be recreated, not just IDs
        record
    }

    fn is_lossless(&self) -> bool {
        // Snapshots lose finalizer implementations
        self.finalizer_count == 0
    }
}
