use crate::observability::{LogEntry, LogLevel};

impl RegionBridge {
    fn log_state_change(&self, operation: &str, result: &CloseResult) {
        LogEntry::new(LogLevel::Info, "bridge_state_change")
            .with_field("region_id", self.id().to_string())
