            .with_field("effective_state", format!("{:?}", result.effective_state))
            .with_field("mode", format!("{:?}", self.mode));
    }

    fn log_mode_upgrade(&self, result: &UpgradeResult) {
        LogEntry::new(LogLevel::Info, "bridge_mode_upgrade")
            .with_field("region_id", self.id().to_string())
            .with_field("from_mode", format!("{:?}", result.previous_mode))
            .with_field("to_mode", format!("{:?}", result.new_mode))
            .with_field("snapshot_sequence", result.snapshot_sequence.to_string());
    }

    fn log_sync_result(&self, result: &SyncResult) {
        let (level, status) = match result {
            SyncResult::NotNeeded => (LogLevel::Trace, "not_needed"),
            SyncResult::Synced { .. } => (LogLevel::Debug, "synced"),
            SyncResult::Pending { .. } => (LogLevel::Debug, "pending"),
            SyncResult::Failed { .. } => (LogLevel::Warn, "failed"),
        };

        LogEntry::new(level, "bridge_sync")
            .with_field("region_id", self.id().to_string())
            .with_field("status", status)
            .with_field("mode", format!("{:?}", self.mode));
    }

    fn log_effective_state_change(&self, prev: EffectiveState, new: EffectiveState) {
        let level = if new.needs_recovery() {
            LogLevel::Warn
        } else {
            LogLevel::Debug
        };

        LogEntry::new(level, "bridge_effective_state_change")
            .with_field("region_id", self.id().to_string())
            .with_field("from", format!("{:?}", prev))
            .with_field("to", format!("{:?}", new))
            .with_field("needs_recovery", new.needs_recovery().to_string());
    }
}

// Log level guidelines:
// - TRACE: Sync not needed, individual operation proxying
// - DEBUG: Sync completed, effective state changes (non-degraded)
// - INFO:  Mode upgrades, lifecycle state changes
// - WARN:  Sync failures, degraded/recovering states, inconsistencies
// - ERROR: Upgrade failures, unrecoverable inconsistencies
